SELECT COUNT(*) 
FROM (
    SELECT ID FROM Laboratory WHERE CRE >= 1.5
) AS abnormal_creatinine 
JOIN (
    SELECT ID, strftime('%Y', 'now') - strftime('%Y', Birthday) AS age FROM Patient
) AS patient_age ON abnormal_creatinine.ID = patient_age.ID
WHERE patient_age.age < 70;

SELECT COUNT(*) FROM (
    SELECT P.ID FROM Patient AS P JOIN Laboratory AS L ON P.ID = L.ID WHERE L.CRE >= 1.5
) AS AbnormalCreatinine WHERE strftime('%Y', 'now') - strftime('%Y', Birthday) < 70;

