WITH MaxAmount AS (
    SELECT MAX(amount) AS max_amount FROM budget WHERE category = 'Food'
)
SELECT remaining FROM budget 
JOIN MaxAmount ON budget.amount = MaxAmount.max_amount 
WHERE budget.category = 'Food';

